-- Acts 17 — Thessalonica, Berea, and the Areopagus
-- Theme: The Unknown God Made Known in the Risen Christ

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 17,
  'Acts 17 advances the second journey through three cities, each revealing a different gospel audience. At Thessalonica Paul reasons for three sabbaths from the Scriptures that the Christ must suffer and rise; many believe, but jealous Jews stir a mob and drag Jason before the rulers. At Berea the Jews are more noble, receiving the word with readiness and searching the Scriptures daily; many believe, until the Thessalonian opposition follows. Paul is escorted to Athens, where his spirit is stirred by an idolatrous city. He disputes in the synagogue and marketplace until Stoics and Epicureans bring him to Mars Hill. There he preaches the masterful Areopagus sermon: the Creator who needs nothing, who has made of one blood all nations, who has appointed a day of judgment, who has furnished proof by raising a man from the dead — Jesus. Some mock, some defer, but certain believe, including Dionysius the Areopagite and Damaris.',
  'The Unknown God Made Known in the Risen Christ',
  'ἀγνοοῦντες',
  'ignorant (agnoountes) — the darkened state of pagan worship, now confronted by the revelation of the true God in Christ (v.23).',
  '[{"range":"vv.1-9","title":"Thessalonica: Three Sabbaths, Then the Uproar"},{"range":"vv.10-15","title":"Berea: More Noble; Searching the Scriptures"},{"range":"vv.16-21","title":"Athens: Stirred in Spirit, Summoned to Mars Hill"},{"range":"vv.22-31","title":"The Areopagus Sermon: Creator, Kinship, and Judgment"},{"range":"vv.32-34","title":"Mockery, Delay, and Some Who Believed"}]'::jsonb
FROM books b WHERE b.name = 'Acts'
ON CONFLICT (book_id, chapter_number) DO UPDATE SET
  overview = EXCLUDED.overview,
  theme = EXCLUDED.theme,
  key_word_original = EXCLUDED.key_word_original,
  key_word_meaning = EXCLUDED.key_word_meaning,
  outline = EXCLUDED.outline;

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'Now when they had passed through Amphipolis and Apollonia, they came to Thessalonica, where was a synagogue of the Jews:',
      'Διοδεύσαντες δὲ τὴν Ἀμφίπολιν καὶ τὴν Ἀπολλωνίαν ἦλθον εἰς Θεσσαλονίκην, ὅπου ἦν συναγωγὴ τῶν Ἰουδαίων.',
      'Diodeusantes de tēn Amphipolin kai tēn Apollōnian ēlthon eis Thessalonikēn, hopou ēn synagōgē tōn Ioudaiōn.',
      'Thessalonica, capital of Macedonia, lay on the Via Egnatia — a strategic hub whose converts would radiate the gospel throughout the province (1 Thess 1:7-8).',
      'Strategic cities are not chosen by the ambition of ministers but by the providence of the Lord who appoints both the cities and the converts there.'),
  (2, 'And Paul, as his manner was, went in unto them, and three sabbath days reasoned with them out of the scriptures,',
      'κατὰ δὲ τὸ εἰωθὸς τῷ Παύλῳ εἰσῆλθεν πρὸς αὐτοὺς καὶ ἐπὶ σάββατα τρία διελέξατο αὐτοῖς ἀπὸ τῶν γραφῶν,',
      'kata de to eiōthos tō Paulō eisēlthen pros autous kai epi sabbata tria dielexato autois apo tōn graphōn,',
      '"His manner" (to eiōthos) — the synagogue-first pattern remains invariable. Dielexato, "dialogued, reasoned," describes structured argument from Scripture, not mere proclamation.',
      'Gospel preaching is rational, exegetical, and scriptural — reasoning from the sacred text, not simply asserting from inward authority.'),
  (3, 'Opening and alleging, that Christ must needs have suffered, and risen again from the dead; and that this Jesus, whom I preach unto you, is Christ.',
      'διανοίγων καὶ παρατιθέμενος ὅτι τὸν χριστὸν ἔδει παθεῖν καὶ ἀναστῆναι ἐκ νεκρῶν, καὶ ὅτι οὗτός ἐστιν ὁ χριστὸς Ἰησοῦς, ὃν ἐγὼ καταγγέλλω ὑμῖν.',
      'dianoigōn kai paratithemenos hoti ton christon edei pathein kai anastēnai ek nekrōn, kai hoti houtos estin ho christos Iēsous, hon egō katangellō hymin.',
      'Dianoigōn, "opening up," the Scriptures; paratithemenos, "setting before them" proofs. Edei ("it was necessary") — the divine necessity that the Messiah suffer (Luke 24:26).',
      'The cross and resurrection of Christ are not tragic accidents but the predetermined divine necessity written in every OT page. True preaching unfolds the suffering-and-rising Christ from Scripture itself.'),
  (4, 'And some of them believed, and consorted with Paul and Silas; and of the devout Greeks a great multitude, and of the chief women not a few.',
      'καί τινες ἐξ αὐτῶν ἐπείσθησαν καὶ προσεκληρώθησαν τῷ Παύλῳ καὶ τῷ Σιλᾷ, τῶν τε σεβομένων Ἑλλήνων πλῆθος πολύ, γυναικῶν τε τῶν πρώτων οὐκ ὀλίγαι.',
      'kai tines ex autōn epeisthēsan kai proseklērōthēsan tō Paulō kai tō Sila, tōn te sebomenōn Hellēnōn plēthos poly, gynaikōn te tōn prōtōn ouk oligai.',
      'Proseklērōthēsan, "were allotted with" — the language of divine assignment: these believers were God''s appointed portion for Paul and Silas. "Chief women" suggests the upper-class patronesses common to Macedonian cities.',
      'Converts are allotted by God to His servants. Believing is not primarily the sinner''s decision but the Lord''s appointment executed through preaching.'),
  (5, 'But the Jews which believed not, moved with envy, took unto them certain lewd fellows of the baser sort, and gathered a company, and set all the city on an uproar, and assaulted the house of Jason, and sought to bring them out to the people.',
      'Ζηλώσαντες δὲ οἱ Ἰουδαῖοι καὶ προσλαβόμενοι τῶν ἀγοραίων ἄνδρας τινὰς πονηροὺς καὶ ὀχλοποιήσαντες ἐθορύβουν τὴν πόλιν, καὶ ἐπιστάντες τῇ οἰκίᾳ Ἰάσονος ἐζήτουν αὐτοὺς προαγαγεῖν εἰς τὸν δῆμον·',
      'Zēlōsantes de hoi Ioudaioi kai proslabomenoi tōn agoraiōn andras tinas ponērous kai ochlopoiēsantes ethoryboun tēn polin, kai epistantes tē oikia Iasonos ezētoun autous proagagein eis ton dēmon;',
      'Zēlōsantes — envious zeal, not holy zeal. They rent a mob from the marketplace (agoraiōn — "loiterers"). Jason, Paul''s host, becomes the target.',
      'Envy is a religious sin that conscripts irreligious allies. The gospel''s success often intensifies its opponents into unholy alliance with the world.'),
  (6, 'And when they found them not, they drew Jason and certain brethren unto the rulers of the city, crying, These that have turned the world upside down are come hither also;',
      'μὴ εὑρόντες δὲ αὐτοὺς ἔσυρον Ἰάσονα καί τινας ἀδελφοὺς ἐπὶ τοὺς πολιτάρχας, βοῶντες ὅτι Οἱ τὴν οἰκουμένην ἀναστατώσαντες οὗτοι καὶ ἐνθάδε πάρεισιν,',
      'mē heurontes de autous esyron Iasona kai tinas adelphous epi tous politarchas, boōntes hoti Hoi tēn oikoumenēn anastatōsantes houtoi kai enthade pareisin,',
      'Politarchēs — an office attested in Thessalonian inscriptions; Luke''s precision confirms his historical reliability. "Turned the world upside down" (anastatōsantes) is an unwitting compliment.',
      'The gospel does indeed overturn the world''s order. Where Christ reigns, idols fall, values invert, and the last become first.'),
  (7, 'Whom Jason hath received: and these all do contrary to the decrees of Caesar, saying that there is another king, one Jesus.',
      'οὓς ὑποδέδεκται Ἰάσων· καὶ οὗτοι πάντες ἀπέναντι τῶν δογμάτων Καίσαρος πράσσουσι, βασιλέα ἕτερον λέγοντες εἶναι Ἰησοῦν.',
      'hous hypodedektai Iasōn; kai houtoi pantes apenanti tōn dogmatōn Kaisaros prassousi, basilea heteron legontes einai Iēsoun.',
      'The charge of treason — proclaiming another king — is both false (politically) and true (ultimately). Jesus is indeed King of kings, but His kingdom does not rival Caesar''s along imperial lines.',
      'Christian allegiance ultimately relativizes every human throne. The King named Jesus reigns over every Caesar who thinks himself supreme.'),
  (8, 'And they troubled the people and the rulers of the city, when they heard these things.',
      'ἐτάραξαν δὲ τὸν ὄχλον καὶ τοὺς πολιτάρχας ἀκούοντας ταῦτα,',
      'etaraxan de ton ochlon kai tous politarchas akouontas tauta,',
      'The charge of treason, plausible under Claudius (who had expelled Jews from Rome), alarms even the magistrates.',
      'False accusation drapes itself in the language of loyalty to the state. Christ''s servants must bear this form of suffering patiently.'),
  (9, 'And when they had taken security of Jason, and of the other, they let them go.',
      'καὶ λαβόντες τὸ ἱκανὸν παρὰ τοῦ Ἰάσονος καὶ τῶν λοιπῶν ἀπέλυσαν αὐτούς.',
      'kai labontes to hikanon para tou Iasonos kai tōn loipōn apelysan autous.',
      '"Security" (to hikanon) — a financial bond guaranteeing peace. This may explain why Paul could not return immediately ("Satan hindered us," 1 Thess 2:18).',
      'Even the enemy''s legal tools bind God''s purposes only for a season. Hindered missionaries are not defeated ones.'),
  (10, 'And the brethren immediately sent away Paul and Silas by night unto Berea: who coming thither went into the synagogue of the Jews.',
      'Οἱ δὲ ἀδελφοὶ εὐθέως διὰ νυκτὸς ἐξέπεμψαν τόν τε Παῦλον καὶ τὸν Σιλᾶν εἰς Βέροιαν, οἵτινες παραγενόμενοι εἰς τὴν συναγωγὴν τῶν Ἰουδαίων ἀπῄεσαν·',
      'Hoi de adelphoi eutheōs dia nyktos exepempsan ton te Paulon kai ton Silan eis Beroian, hoitines paragenomenoi eis tēn synagōgēn tōn Ioudaiōn apēesan;',
      'Night escort by the brethren — a new church protecting its apostles. Berea lay some 50 miles southwest.',
      'The young church''s first love expresses itself as protective action for the apostles who planted them. Spiritual parenthood is a two-way bond.'),
  (11, 'These were more noble than those in Thessalonica, in that they received the word with all readiness of mind, and searched the scriptures daily, whether those things were so.',
      'οὗτοι δὲ ἦσαν εὐγενέστεροι τῶν ἐν Θεσσαλονίκῃ, οἵτινες ἐδέξαντο τὸν λόγον μετὰ πάσης προθυμίας, καθ᾽ ἡμέραν ἀνακρίνοντες τὰς γραφὰς εἰ ἔχοι ταῦτα οὕτως.',
      'houtoi de ēsan eugenesteroi tōn en Thessalonikē, hoitines edexanto ton logon meta pasēs prothymias, kath hēmeran anakrinontes tas graphas ei echoi tauta houtōs.',
      'Eugenesteroi, "more noble-born," metaphorically "more open-minded." Prothymias, "eagerness." Anakrinontes, "examining judicially." The Bereans neither swallow the apostle''s word uncritically nor reject it without hearing — they measure it by Scripture.',
      'True nobility of soul welcomes the word eagerly yet tests it by Scripture. The Bereans set the perpetual standard: receive with readiness, examine with the written Word.'),
  (12, 'Therefore many of them believed; also of honourable women which were Greeks, and of men, not a few.',
      'πολλοὶ μὲν οὖν ἐξ αὐτῶν ἐπίστευσαν, καὶ τῶν Ἑλληνίδων γυναικῶν τῶν εὐσχημόνων καὶ ἀνδρῶν οὐκ ὀλίγοι.',
      'polloi men oun ex autōn episteusan, kai tōn Hellēnidōn gynaikōn tōn euschēmonōn kai andrōn ouk oligoi.',
      'The fruit of Scripture-searching is faith. Study and belief are friends, not foes, when Scripture is the object.',
      'Faith born of Scripture-examination is durable faith. Doubt that leads a man to the Book is on the road to belief.'),
  (13, 'But when the Jews of Thessalonica had knowledge that the word of God was preached of Paul at Berea, they came thither also, and stirred up the people.',
      'Ὡς δὲ ἔγνωσαν οἱ ἀπὸ τῆς Θεσσαλονίκης Ἰουδαῖοι ὅτι καὶ ἐν τῇ Βεροίᾳ κατηγγέλη ὑπὸ τοῦ Παύλου ὁ λόγος τοῦ θεοῦ, ἦλθον κἀκεῖ σαλεύοντες καὶ ταράσσοντες τοὺς ὄχλους.',
      'Hōs de egnōsan hoi apo tēs Thessalonikēs Ioudaioi hoti kai en tē Beroia katēngelē hypo tou Paulou ho logos tou theou, ēlthon kakei saleuontes kai tarassontes tous ochlous.',
      'The Thessalonian opposition travels 50 miles to continue the pursuit. Saleuontes, "shaking," the same verb as "earthquake" (16:26) — a satanic counter-movement against the shaking that delivered the jailer.',
      'Persistent enemies pursue the gospel from city to city. Satan''s malice is tireless; Christ''s grace is more tireless still.'),
  (14, 'And then immediately the brethren sent away Paul to go as it were to the sea: but Silas and Timotheus abode there still.',
      'εὐθέως δὲ τότε τὸν Παῦλον ἐξαπέστειλαν οἱ ἀδελφοὶ πορεύεσθαι ἕως ἐπὶ τὴν θάλασσαν, ὑπέμειναν δὲ ὅ τε Σιλᾶς καὶ ὁ Τιμόθεος ἐκεῖ.',
      'eutheōs de tote ton Paulon exapesteilan hoi adelphoi poreuesthai heōs epi tēn thalassan, hypemeinan de ho te Silas kai ho Timotheos ekei.',
      'Silas and Timothy remain to shepherd the young church; Paul is the chief target and is moved southward.',
      'The seasoned apostle withdraws; the younger ministers stand firm. The church''s care of her leaders sometimes separates to protect and preserve.'),
  (15, 'And they that conducted Paul brought him unto Athens: and receiving a commandment unto Silas and Timotheus for to come to him with all speed, they departed.',
      'οἱ δὲ καθιστάνοντες τὸν Παῦλον ἤγαγον ἕως Ἀθηνῶν, καὶ λαβόντες ἐντολὴν πρὸς τὸν Σιλᾶν καὶ τὸν Τιμόθεον ἵνα ὡς τάχιστα ἔλθωσιν πρὸς αὐτὸν ἐξῄεσαν.',
      'hoi de kathistanontes ton Paulon ēgagon heōs Athēnōn, kai labontes entolēn pros ton Silan kai ton Timotheon hina hōs tachista elthōsin pros auton exēesan.',
      'Athens, though no longer the political capital, remained the intellectual center of the Greek world. Paul waits alone among its altars.',
      'The apostle who breathes best in the furnace of opposition must sometimes wait, alone and grieved, in the city of ideas. Faithfulness includes solitary waiting.'),
  (16, 'Now while Paul waited for them at Athens, his spirit was stirred in him, when he saw the city wholly given to idolatry.',
      'Ἐν δὲ ταῖς Ἀθήναις ἐκδεχομένου αὐτοὺς τοῦ Παύλου, παρωξύνετο τὸ πνεῦμα αὐτοῦ ἐν αὐτῷ θεωροῦντος κατείδωλον οὖσαν τὴν πόλιν.',
      'En de tais Athēnais ekdechomenou autous tou Paulou, parōxyneto to pneuma autou en autō theōrountos kateidōlon ousan tēn polin.',
      'Parōxyneto — "was paroxysmed," sharply stirred. The same root as paroxysmos (15:39). Kateidōlon ("full of idols") is a unique NT word. Contemporary witnesses estimated 30,000 images in Athens.',
      'Holy love for Christ cannot walk calmly through a forest of idols. The saint''s heart beats hot where God''s glory is stolen.'),
  (17, 'Therefore disputed he in the synagogue with the Jews, and with the devout persons, and in the market daily with them that met with him.',
      'διελέγετο μὲν οὖν ἐν τῇ συναγωγῇ τοῖς Ἰουδαίοις καὶ τοῖς σεβομένοις καὶ ἐν τῇ ἀγορᾷ κατὰ πᾶσαν ἡμέραν πρὸς τοὺς παρατυγχάνοντας.',
      'dielegeto men oun en tē synagōgē tois Ioudaiois kai tois sebomenois kai en tē agora kata pasan hēmeran pros tous paratynchanontas.',
      'Paul does both synagogue exposition and agora dialogue — formal theology to God-fearers and public conversation to any who happened by. Socrates himself had disputed in this same marketplace 450 years earlier.',
      'Christian apologetic speaks in every forum — religious and secular, scheduled and spontaneous. The whole world is the apostle''s classroom.'),
  (18, 'Then certain philosophers of the Epicureans, and of the Stoicks, encountered him. And some said, What will this babbler say? other some, He seemeth to be a setter forth of strange gods: because he preached unto them Jesus, and the resurrection.',
      'τινὲς δὲ καὶ τῶν Ἐπικουρείων καὶ Στοϊκῶν φιλοσόφων συνέβαλλον αὐτῷ, καί τινες ἔλεγον· Τί ἂν θέλοι ὁ σπερμολόγος οὗτος λέγειν; οἱ δέ· Ξένων δαιμονίων δοκεῖ καταγγελεὺς εἶναι· ὅτι τὸν Ἰησοῦν καὶ τὴν ἀνάστασιν εὐηγγελίζετο.',
      'tines de kai tōn Epikoureiōn kai Stoikōn philosophōn syneballon autō, kai tines elegon; Ti an theloi ho spermologos houtos legein? hoi de; Xenōn daimoniōn dokei katangeleus einai; hoti ton Iēsoun kai tēn anastasin euēngelizeto.',
      'Epicureans pursued tranquil pleasure and denied providence; Stoics pursued virtue through reason and equated God with nature''s soul. "Babbler" (spermologos) = "seed-picker," a scavenger-bird; a contemptuous epithet.',
      'Every age offers the two dominant errors — hedonism and moralism. Both must hear Christ crucified and risen; both are equally dead without Him.'),
  (19, 'And they took him, and brought him unto Areopagus, saying, May we know what this new doctrine, whereof thou speakest, is?',
      'ἐπιλαβόμενοί τε αὐτοῦ ἐπὶ τὸν Ἄρειον πάγον ἤγαγον λέγοντες· Δυνάμεθα γνῶναι τίς ἡ καινὴ αὕτη ἡ ὑπὸ σοῦ λαλουμένη διδαχή;',
      'epilabomenoi te autou epi ton Areion pagon ēgagon legontes; Dynametha gnōnai tis hē kainē hautē hē hypo sou laloumenē didachē?',
      'The Areopagus ("Mars Hill") was the ancient Athenian council that supervised religion, morals, and education. Paul is brought for inquiry, not trial.',
      'The gospel is willing to be heard by any council. Christ does not fear cross-examination; He invites it.'),
  (20, 'For thou bringest certain strange things to our ears: we would know therefore what these things mean.',
      'ξενίζοντα γάρ τινα εἰσφέρεις εἰς τὰς ἀκοὰς ἡμῶν· βουλόμεθα οὖν γνῶναι τίνα θέλει ταῦτα εἶναι.',
      'xenizonta gar tina eispherеis eis tas akoas hēmōn; boulometha oun gnōnai tina thelei tauta einai.',
      'Xenizonta, "strange, foreign-sounding." Athenian curiosity, not yet hostile, affords the apostle his hearing.',
      'Even shallow curiosity opens doors the Spirit fills with weight. The apostle preaches through any door providence opens.'),
  (21, '(For all the Athenians and strangers which were there spent their time in nothing else, but either to tell, or to hear some new thing.)',
      'Ἀθηναῖοι δὲ πάντες καὶ οἱ ἐπιδημοῦντες ξένοι εἰς οὐδὲν ἕτερον ηὐκαίρουν ἢ λέγειν τι ἢ ἀκούειν τι καινότερον.',
      'Athēnaioi de pantes kai hoi epidēmountes xenoi eis ouden heteron ēukairoun ē legein ti ē akouein ti kainoteron.',
      'Luke''s parenthetical ethnography. Athens''s intellectual fashion was addicted to novelty — the same modern sickness in academic garb.',
      'Novelty is the enemy of truth wherever curiosity replaces conviction. The gospel is ancient and new at once; it answers the itch it does not indulge.'),
  (22, 'Then Paul stood in the midst of Mars'' hill, and said, Ye men of Athens, I perceive that in all things ye are too superstitious.',
      'Σταθεὶς δὲ Παῦλος ἐν μέσῳ τοῦ Ἀρείου πάγου ἔφη· Ἄνδρες Ἀθηναῖοι, κατὰ πάντα ὡς δεισιδαιμονεστέρους ὑμᾶς θεωρῶ·',
      'Statheis de Paulos en mesō tou Areiou pagou ephē; Andres Athēnaioi, kata panta hōs deisidaimonesterous hymas theōrō;',
      'Deisidaimonesterous is ambiguous — "very religious" or "very superstitious." Paul opens diplomatically, acknowledging their reverence without yet endorsing it.',
      'Gospel wisdom begins where people are. The preacher acknowledges genuine religious longing before confronting error.'),
  (23, 'For as I passed by, and beheld your devotions, I found an altar with this inscription, TO THE UNKNOWN GOD. Whom therefore ye ignorantly worship, him declare I unto you.',
      'διερχόμενος γὰρ καὶ ἀναθεωρῶν τὰ σεβάσματα ὑμῶν εὗρον καὶ βωμὸν ἐν ᾧ ἐπεγέγραπτο· Ἀγνώστῳ θεῷ. ὃ οὖν ἀγνοοῦντες εὐσεβεῖτε, τοῦτο ἐγὼ καταγγέλλω ὑμῖν.',
      'dierchomenos gar kai anatheōrōn ta sebasmata hymōn heuron kai bōmon en hō epegegrapto; Agnōstō theō. ho oun agnoountes eusebeite, touto egō katangellō hymin.',
      'Altars "to unknown gods" were attested in Athens by Pausanias (2nd c. AD). Paul seizes their confessed ignorance as his contact-point. Agnoountes, "being ignorant," names the problem their altar acknowledges.',
      'The truest human religion confesses its own ignorance. Revelation alone can fill the unknown; Christ alone is the God now made known.'),
  (24, 'God that made the world and all things therein, seeing that he is Lord of heaven and earth, dwelleth not in temples made with hands;',
      'ὁ θεὸς ὁ ποιήσας τὸν κόσμον καὶ πάντα τὰ ἐν αὐτῷ, οὗτος οὐρανοῦ καὶ γῆς ὑπάρχων κύριος οὐκ ἐν χειροποιήτοις ναοῖς κατοικεῖ,',
      'ho theos ho poiēsas ton kosmon kai panta ta en autō, houtos ouranou kai gēs hyparchōn kyrios ouk en cheiropoiētois naois katoikei,',
      'Paul begins with Creator-Lord, echoing Gen 1:1 and Isa 66:1-2. "Made with hands" (cheiropoiētois) recalls Stephen''s sermon (7:48) — a direct blow to the Parthenon in view.',
      'The God who made all cannot be housed in any. All human religion that confines God to shrines is a diminishment of His majesty.'),
  (25, 'Neither is worshipped with men''s hands, as though he needed any thing, seeing he giveth to all life, and breath, and all things;',
      'οὐδὲ ὑπὸ χειρῶν ἀνθρωπίνων θεραπεύεται προσδεόμενός τινος, αὐτὸς διδοὺς πᾶσι ζωὴν καὶ πνοὴν καὶ τὰ πάντα·',
      'oude hypo cheirōn anthrōpinōn therapeuetai prosdeomenos tinos, autos didous pasi zōēn kai pnoēn kai ta panta;',
      'God is aseity itself — existing independently, needing nothing (Ps 50:9-12). He gives; He does not need to be given to.',
      'The true God is infinitely self-sufficient. Worship is not supplying Him but receiving from Him with thankful hands.'),
  (26, 'And hath made of one blood all nations of men for to dwell on all the face of the earth, and hath determined the times before appointed, and the bounds of their habitation;',
      'ἐποίησέν τε ἐξ ἑνὸς πᾶν ἔθνος ἀνθρώπων κατοικεῖν ἐπὶ παντὸς προσώπου τῆς γῆς, ὁρίσας προστεταγμένους καιροὺς καὶ τὰς ὁροθεσίας τῆς κατοικίας αὐτῶν,',
      'epoiēsen te ex henos pan ethnos anthrōpōn katoikein epi pantos prosōpou tēs gēs, horisas prostetagmenous kairous kai tas horothesias tēs katoikias autōn,',
      '"Of one blood" (ex henos, "from one") — Paul affirms the unity of humanity in Adam, cutting against Greek ethnic pride that disdained barbarians. God has ordered "times" (epochs) and "bounds" (national borders).',
      'All nations share one blood and one Maker. Rise and fall of empires, chart of every continent, is ordained by God to bring men to seek Him.'),
  (27, 'That they should seek the Lord, if haply they might feel after him, and find him, though he be not far from every one of us:',
      'ζητεῖν τὸν θεὸν εἰ ἄρα γε ψηλαφήσειαν αὐτὸν καὶ εὕροιεν, καί γε οὐ μακρὰν ἀπὸ ἑνὸς ἑκάστου ἡμῶν ὑπάρχοντα.',
      'zētein ton theon ei ara ge psēlaphēseian auton kai heuroien, kai ge ou makran apo henos hekastou hēmōn hyparchonta.',
      'Psēlaphēseian, "might grope" — the blind reaching of the human heart after unseen reality. God''s nearness to every man is real; man''s ignorance of that nearness is tragic.',
      'God has so ordered history that the nations might grope after Him. He is near to every man; only sin blinds man to the One who is closer than breath.'),
  (28, 'For in him we live, and move, and have our being; as certain also of your own poets have said, For we are also his offspring.',
      'ἐν αὐτῷ γὰρ ζῶμεν καὶ κινούμεθα καὶ ἐσμέν· ὡς καί τινες τῶν καθ᾽ ὑμᾶς ποιητῶν εἰρήκασιν· Τοῦ γὰρ καὶ γένος ἐσμέν.',
      'en autō gar zōmen kai kinoumetha kai esmen; hōs kai tines tōn kath hymas poiētōn eirēkasin; Tou gar kai genos esmen.',
      'Paul quotes Epimenides of Crete and Aratus''s Phaenomena — pagan poets who dimly saw the truth. Common grace has left partial insights even in unbelievers; these may be borrowed to witness to Christ.',
      'The Christian may appropriate pagan truth wherever truth is found, redirecting it to the Author of truth. Creation''s witness to God outlasts even idolatry.'),
  (29, 'Forasmuch then as we are the offspring of God, we ought not to think that the Godhead is like unto gold, or silver, or stone, graven by art and man''s device.',
      'γένος οὖν ὑπάρχοντες τοῦ θεοῦ οὐκ ὀφείλομεν νομίζειν χρυσῷ ἢ ἀργύρῳ ἢ λίθῳ, χαράγματι τέχνης καὶ ἐνθυμήσεως ἀνθρώπου, τὸ θεῖον εἶναι ὅμοιον.',
      'genos oun hyparchontes tou theou ouk opheilomen nomizein chrysō ē argyrō ē lithō, charagmati technēs kai enthymēseōs anthrōpou, to theion einai homoion.',
      'The argument from the greater to the lesser: if we His offspring are spirit and intellect, how much less can the God who made us be mere metal or stone? Cf. Isa 44:9-20.',
      'Man made in God''s image cannot rightly worship what is less than himself. Every idol is a self-contradiction of the very image it perverts.'),
  (30, 'And the times of this ignorance God winked at; but now commandeth all men every where to repent:',
      'τοὺς μὲν οὖν χρόνους τῆς ἀγνοίας ὑπεριδὼν ὁ θεὸς τὰ νῦν παραγγέλλει τοῖς ἀνθρώποις πάντας πανταχοῦ μετανοεῖν,',
      'tous men oun chronous tēs agnoias hyperidōn ho theos ta nyn parangellei tois anthrōpois pantas pantachou metanoein,',
      'Hyperidōn, "having overlooked" — not approved, but patiently borne (cf. 14:16; Rom 3:25). The universal summons to repent (metanoein) is issued "now" because of the finished work of Christ.',
      'Common grace toleration of past pagan ignorance is now superseded by a universal gospel summons. The cross and resurrection have changed the terms of history.'),
  (31, 'Because he hath appointed a day, in the which he will judge the world in righteousness by that man whom he hath ordained; whereof he hath given assurance unto all men, in that he hath raised him from the dead.',
      'καθότι ἔστησεν ἡμέραν ἐν ᾗ μέλλει κρίνειν τὴν οἰκουμένην ἐν δικαιοσύνῃ ἐν ἀνδρὶ ᾧ ὥρισεν, πίστιν παρασχὼν πᾶσιν ἀναστήσας αὐτὸν ἐκ νεκρῶν.',
      'kathoti estēsen hēmeran en hē mellei krinein tēn oikoumenēn en dikaiosynē en andri hō hōrisen, pistin paraschōn pasin anastēsas auton ek nekrōn.',
      'The sermon climaxes with judgment and resurrection. God has "furnished proof" (pistin paraschōn) by raising Jesus. The resurrection is God''s public evidence that the Judge has been appointed.',
      'The resurrection is the centerpiece of history. It is both the guarantee of coming judgment and the only credential worth trusting for the One who will sit in it.'),
  (32, 'And when they heard of the resurrection of the dead, some mocked: and others said, We will hear thee again of this matter.',
      'ἀκούσαντες δὲ ἀνάστασιν νεκρῶν οἱ μὲν ἐχλεύαζον, οἱ δὲ εἶπαν· Ἀκουσόμεθά σου περὶ τούτου καὶ πάλιν.',
      'akousantes de anastasin nekrōn hoi men echleuazon, hoi de eipan; Akousometha sou peri toutou kai palin.',
      'Three responses: mockery, deferral, and belief (v.34). Greek philosophy found bodily resurrection absurd (cf. "ghosts," "shades"). Mockery often cloaks fear.',
      'The resurrection dividing point settles every hearer. Laughter, postponement, and faith are the three doors out of every pulpit.'),
  (33, 'So Paul departed from among them.',
      'οὕτως ὁ Παῦλος ἐξῆλθεν ἐκ μέσου αὐτῶν·',
      'houtōs ho Paulos exēlthen ek mesou autōn;',
      'The apostle does not linger to debate. When the hearing is concluded, he leaves, letting the word do its work.',
      'Ministers preach, then yield the verdict. The Spirit, not persuasion, saves.'),
  (34, 'Howbeit certain men clave unto him, and believed: among the which was Dionysius the Areopagite, and a woman named Damaris, and others with them.',
      'τινὲς δὲ ἄνδρες κολληθέντες αὐτῷ ἐπίστευσαν, ἐν οἷς καὶ Διονύσιος ὁ Ἀρεοπαγίτης καὶ γυνὴ ὀνόματι Δάμαρις καὶ ἕτεροι σὺν αὐτοῖς.',
      'tines de andres kollēthentes autō episteusan, en hois kai Dionysios ho Areopagitēs kai gynē onomati Damaris kai heteroi syn autois.',
      'Kollēthentes, "glued" — unbreakable attachment. Dionysius was a member of the Areopagus council itself; tradition makes him first bishop of Athens. Damaris is the only woman named in the conversions of chapter 17.',
      'Even amid mockery and deferral, sovereign grace reaches the heart of an Areopagite. The gospel never preaches in vain; the Word claims its elect in every city.')
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Acts' AND c.chapter_number = 17
ON CONFLICT (chapter_id, verse_number) DO UPDATE SET
  kjv_text = EXCLUDED.kjv_text,
  original_text = EXCLUDED.original_text,
  transliteration = EXCLUDED.transliteration,
  study_note = EXCLUDED.study_note,
  doctrinal_note = EXCLUDED.doctrinal_note;

INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (2, 'εἰωθὸς', 'eiōthos', 'G1486', 'Custom, habit — Paul''s invariable pattern of going first to the synagogue.', 1),
  (2, 'διελέξατο', 'dielexato', 'G1256', 'Reasoned, dialogued — structured exegetical argument from Scripture.', 2),
  (3, 'διανοίγων', 'dianoigōn', 'G1272', 'Opening up, unlocking — opening the Scriptures as Christ did in Luke 24:45.', 3),
  (3, 'παρατιθέμενος', 'paratithemenos', 'G3908', 'Setting before, presenting — laying out evidence methodically.', 4),
  (3, 'ἔδει παθεῖν', 'edei pathein', 'G1163/G3958', 'It was necessary to suffer — the divine necessity of the cross (Luke 24:26).', 5),
  (4, 'προσεκληρώθησαν', 'proseklērōthēsan', 'G4345', 'Were allotted with — divinely assigned as the apostle''s portion.', 6),
  (5, 'ζηλώσαντες', 'zēlōsantes', 'G2206', 'Being envious — religious envy stirring opposition to the gospel.', 7),
  (5, 'ἀγοραίων', 'agoraiōn', 'G60', 'Loafers of the marketplace — lowlife rabble hired for mob work.', 8),
  (6, 'πολιτάρχας', 'politarchas', 'G4173', 'Politarchs — civic rulers; title attested only in Thessalonian inscriptions.', 9),
  (6, 'ἀναστατώσαντες', 'anastatōsantes', 'G387', 'Turned upside down, overturned — unwitting testimony to the gospel''s world-transforming power.', 10),
  (7, 'βασιλέα ἕτερον', 'basilea heteron', 'G935/G2087', 'Another king — the charge of political sedition leveled against Christ''s kingship.', 11),
  (9, 'ἱκανὸν', 'hikanon', 'G2425', 'Sufficient, security bond — financial surety for peace.', 12),
  (11, 'εὐγενέστεροι', 'eugenesteroi', 'G2104', 'More noble-minded — open-minded but not credulous.', 13),
  (11, 'προθυμίας', 'prothymias', 'G4288', 'Eagerness, readiness — the glad receptivity of the true hearer.', 14),
  (11, 'ἀνακρίνοντες', 'anakrinontes', 'G350', 'Examining judicially — testing by Scripture as the final court.', 15),
  (13, 'σαλεύοντες', 'saleuontes', 'G4531', 'Agitating, shaking — satanic counter-earthquake against God''s quake of deliverance.', 16),
  (16, 'παρωξύνετο', 'parōxyneto', 'G3947', 'Was provoked/stirred — holy indignation at idolatry.', 17),
  (16, 'κατείδωλον', 'kateidōlon', 'G2712', 'Full of idols — unique NT word describing saturated idolatry.', 18),
  (17, 'διελέγετο', 'dielegeto', 'G1256', 'Reasoned, dialogued — sustained public argument for Christ.', 19),
  (18, 'Ἐπικουρείων', 'Epikoureiōn', 'G1946', 'Epicureans — philosophers of pleasure, denying providence and afterlife.', 20),
  (18, 'Στοϊκῶν', 'Stoikōn', 'G4770', 'Stoics — pantheistic moralists seeking virtue through impassivity.', 21),
  (18, 'σπερμολόγος', 'spermologos', 'G4691', 'Seed-picker, babbler — contemptuous term for a scrounging scavenger.', 22),
  (19, 'Ἄρειον πάγον', 'Areion pagon', 'G697', 'Mars Hill/Areopagus — the ancient Athenian council of elders.', 23),
  (20, 'ξενίζοντα', 'xenizonta', 'G3579', 'Strange, foreign — novel to Athenian ears.', 24),
  (22, 'δεισιδαιμονεστέρους', 'deisidaimonesterous', 'G1174', 'Religious/superstitious — diplomatically ambiguous opening.', 25),
  (23, 'ἀγνώστῳ θεῷ', 'agnōstō theō', 'G57/G2316', 'To the unknown god — Athenian altar inscription becoming gospel contact-point.', 26),
  (23, 'ἀγνοοῦντες', 'agnoountes', 'G50', 'Being ignorant — chapter''s keyword, pagan worship confessed as blind.', 27),
  (24, 'χειροποιήτοις', 'cheiropoiētois', 'G5499', 'Made with hands — OT phrase for idols (Lev 26:1); echoes Stephen (7:48).', 28),
  (25, 'προσδεόμενός', 'prosdeomenos', 'G4326', 'Needing in addition — God lacks nothing; He is absolutely self-sufficient.', 29),
  (25, 'πνοὴν', 'pnoēn', 'G4157', 'Breath — echoes Gen 2:7, God breathing life into man.', 30),
  (26, 'ἐξ ἑνὸς', 'ex henos', 'G1520', 'From one — the unity of the human race in Adam.', 31),
  (26, 'ὁροθεσίας', 'horothesias', 'G3734', 'Boundaries — the fixed limits of nations sovereignly determined.', 32),
  (27, 'ψηλαφήσειαν', 'psēlaphēseian', 'G5584', 'Might grope — the blind reaching of darkened humanity after God.', 33),
  (28, 'γένος', 'genos', 'G1085', 'Offspring, kind — general creatorship (not salvific sonship).', 34),
  (29, 'χαράγματι', 'charagmati', 'G5480', 'Engraving, image — fashioned idol made by hand and mind.', 35),
  (30, 'ὑπεριδὼν', 'hyperidōn', 'G5237', 'Having overlooked — past toleration of ignorance now ended.', 36),
  (30, 'μετανοεῖν', 'metanoein', 'G3340', 'To repent — mind-change toward God; universal summons now issued.', 37),
  (31, 'ἔστησεν ἡμέραν', 'estēsen hēmeran', 'G2476/G2250', 'Has appointed a day — fixed divine verdict-day of world judgment.', 38),
  (31, 'πίστιν παρασχὼν', 'pistin paraschōn', 'G4102/G3930', 'Having furnished proof/assurance — resurrection as public evidence.', 39),
  (31, 'ἀναστήσας', 'anastēsas', 'G450', 'Having raised up — the resurrection is the divine vindication of Jesus.', 40),
  (32, 'ἐχλεύαζον', 'echleuazon', 'G5512', 'Mocked, scoffed — typical philosophical dismissal of bodily resurrection.', 41),
  (34, 'κολληθέντες', 'kollēthentes', 'G2853', 'Glued, joined — inseparable attachment of true converts.', 42),
  (34, 'Ἀρεοπαγίτης', 'Areopagitēs', 'G698', 'Areopagite — member of the Athenian high council.', 43)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Acts' AND c.chapter_number = 17 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

